#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int good = 1;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if (x <= 4) good = 0;
        }
        printf(good ? "YES\n" : "NO\n");
    }
    return 0;
}

